// The postcondition is `LHS ==> det_endpoint_to_page_equal(r1, r2)`.
// `r1` and `r2` are arbitrary tuple parameters; the LHS conjuncts are NOT
// premises of the proof, they are the antecedent of the implication we
// must discharge. So we can't assert them directly; instead we guard our
// reasoning with `if (LHS) { ... }`, which makes the conjuncts available
// as hypotheses inside the branch. Within the branch we derive the two
// halves of `det_endpoint_to_page_equal`:
//   * `r1.0 == r2.0` — both pinned to `endpoint_ptr`.
//   * `r1.1@ == r2.1@` — both `PointsTo` views agree on `addr()` and
//     `is_init()`; lift to extensional equality via `=~=`.
if (r1.0 == endpoint_ptr)
    && (r1.1@.is_init())
    && (r1.1@.addr() == endpoint_ptr)
    && (r2.0 == endpoint_ptr)
    && (r2.1@.is_init())
    && (r2.1@.addr() == endpoint_ptr)
{
    // First conjunct of det_endpoint_to_page_equal: PagePtr halves.
    assert(r1.0 == endpoint_ptr);
    assert(r2.0 == endpoint_ptr);
    assert(r1.0 == r2.0);

    // Per-projection equalities on the PointsTo views.
    assert(r1.1@.addr() == endpoint_ptr);
    assert(r2.1@.addr() == endpoint_ptr);
    assert(r1.1@.addr() == r2.1@.addr());

    assert(r1.1@.is_init());
    assert(r2.1@.is_init());
    assert(r1.1@.is_init() == r2.1@.is_init());

    // Lift the per-projection equalities to extensional equality on the
    // PointsTo view structs.
    assert(r1.1@ =~= r2.1@);

    // Close the determinism equality.
    assert(det_endpoint_to_page_equal(r1, r2));
}
